const AWS = require('aws-sdk');
const https = require('https');

const sqs = new AWS.SQS({ region: 'us-east-1' });
const dynamoDb = new AWS.DynamoDB.DocumentClient({ region: 'us-east-1' });

exports.handler = async (event) => {
    const queueUrl = 'https://sqs.us-east-1.amazonaws.com/123456789012/my-queue';

    try {
        // Receive messages from SQS
        const receiveParams = { QueueUrl: queueUrl, MaxNumberOfMessages: 10 };
        let response = await sqs.receiveMessage(receiveParams).promise();
        const messages = response.Messages;

        if (messages && messages.length > 0) {
            for (const message of messages) {
                try {
                    // Process each message
                    const order = JSON.parse(message.Body);
                    const paymentResponse = await callPaymentApi(order);

                    // Update DynamoDB with payment status
                    const updateParams = {
                        TableName: 'Orders',
                        Key: { orderId: order.orderId },
                        UpdateExpression: 'set #status = :status, #paymentDetails = :paymentDetails',
                        ExpressionAttributeNames: { '#status': 'status', '#paymentDetails': 'paymentDetails' },
                        ExpressionAttributeValues: { ':status': paymentResponse.status, ':paymentDetails': paymentResponse.details }
                    };
                    await dynamoDb.update(updateParams).promise();

                    // Delete message from SQS
                    const deleteParams = {
                        QueueUrl: queueUrl,
                        ReceiptHandle: message.ReceiptHandle
                    };
                    await sqs.deleteMessage(deleteParams).promise();
                } catch (error) {
                    console.error('Error processing message:', error);
                }
            }
        }
    } catch (error) {
        console.error('Error receiving messages from SQS:', error);
    }
};

async function callPaymentApi(order) {
    return new Promise((resolve, reject) => {
        const options = {
            hostname: 'paymentapi.example.com',
            path: '/process',
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            }
        };

        const req = https.request(options, (res) => {
            let data = '';
            res.on('data', (chunk) => {
                data += chunk;
            });
            res.on('end', () => {
                try {
                    const paymentResponse = JSON.parse(data);
                    resolve(paymentResponse);
                } catch (error) {
                    reject(error);
                }
            });
        });

        req.on('error', (error) => {
            reject(error);
        });

        req.write(JSON.stringify(order));
        req.end();
    });
}